<template>
  <div class="screen-container">
    <div class="screen-scale" :style="scaleStyle">
      <ScreenHeader title="职业技能等级认定理论考试" />
      <main class="screen-body">
        <section class="card card-left">
          <div class="card-title-dark">评价职业</div>
          <div class="card-content">
            <div class="job-grid">
              <div v-for="(item, index) in jobdata" :key="index" class="job-card">
                <div class="job-name">{{ item.jobName }}</div>
                <div class="job-level">{{ item.jobLevel }}</div>
              </div>
            </div>
          </div>
        </section>
        <section class="card-right">
          <div class="card-right-item">
            <div class="card-title">考试时间</div>
            <div class="card-content">
              <div class="text-line">{{ examTime }}</div>
            </div>
          </div>
          <div class="card-right-item">
            <div class="card-title">准考证号</div>
            <div class="card-content exam-ticket">
              <div class="text-line">{{ admissionTicket }}（{{ ticketDesc }}）</div>
            </div>
          </div>
        </section>
      </main>
      <footer class="screen-footer">
        <span class="tip-label">温馨提示：请等待叫号依次参加实操考试，</span>
        <span class="tip-text">若已过号请等待重新叫号</span>
      </footer>
    </div>
  </div>
</template>

<script>
import ScreenHeader from "./screenTop.vue";
import { getPracticalexamination } from "@/api/screen/screen";
export default {
  name: "ScreenIndex3",
  components: {
    ScreenHeader,
  },
  data() {
    return {
      designWidth: 2200,
      designHeight: 1090,
      scale: 1,
      offsetX: 0,
      offsetY: 0,
      jobdata: [
        {
          jobName: "养老护理员",
          jobLevel: "五级",
        },
        {
          jobName: "婴幼儿发展引导员",
          jobLevel: "四级",
        },
        {
          jobName: "健康照护师",
          jobLevel: "三级",
        },
        {
          jobName: "育婴员",
          jobLevel: "二级",
        },
        {
          jobName: "家政服务员",
          jobLevel: "一级",
        },
        {
          jobName: "养老护理员",
          jobLevel: "一级",
        },
      ],
      examTime: "2026年4月27日 8:00-9:00",
      teachers: ["王建立", "张贤亮", "刘宇"],
      admissionTicket: null,
      ticketDesc: "19位准考证编号",
    };
  },
  computed: {
    scaleStyle() {
      return {
        width: `${this.designWidth}px`,
        height: `${this.designHeight}px`,
        transform: `scale(${this.scale})`,
        left: `${this.offsetX}px`,
        top: `${this.offsetY}px`,
      };
    },
  },
  methods: {
    getData() {
      getPracticalexamination().then(res => {
        console.log(res);
        if (res && res.state) {
          const data = res.data;
          const list = Array.isArray(data) ? data : (data ? [data] : []);
          if (list.length) {
            this.jobdata = list
                .map((item) => ({
                  jobName: item.jobName !== undefined ? item.jobName : item.job,
                  jobLevel: item.jobLevel !== undefined ? item.jobLevel : item.level,
                }))
                .filter((item) => item.jobName || item.jobLevel);
            const first = list[0] || {};
            const start = first.examTime || "";
            const end = first.endTime || "";
            if (start && end) this.examTime = `${start} 到 ${end}`;
            else if (start) this.examTime = start;
            else if (end) this.examTime = end;
            if (first.admissionTicket !== undefined) this.admissionTicket = first.admissionTicket;
          }
        }
      })
    },
    updateScale() {
      const vw =
          window.innerWidth ||
          document.documentElement.clientWidth ||
          this.designWidth;
      const vh =
          window.innerHeight ||
          document.documentElement.clientHeight ||
          this.designHeight;
      const scaleX = vw / this.designWidth;
      const scaleY = vh / this.designHeight;
      const scale = Math.min(scaleX, scaleY);
      this.scale = scale > 0 ? scale : 1;
      this.offsetX = Math.max(0, (vw - this.designWidth * this.scale) / 2);
      this.offsetY = Math.max(0, (vh - this.designHeight * this.scale) / 2);
    },
    handleResize() {
      this.updateScale();
    },
  },
  mounted() {
    this.getData()
    this.updateScale();
    window.addEventListener("resize", this.handleResize);
  },
  beforeDestroy() {
    window.removeEventListener("resize", this.handleResize);
  },
};
</script>

