  line-height: 110px;
  margin: 18px 18px 0;
  font-weight: 500;
  font-size: 50px;
}

.card-content {
  padding: 25px;
  box-sizing: border-box;
  height: 204px;
  background: #fff;
  border-radius: 0px 0px 20px 20px;
  font-weight: 400;
  font-size: 42px;
  color: #1a1a1a;
}

.exam-ticket {
  height: 395px;
}

.text-line {
